<script setup lang="ts">
import { CalendarDays, ChevronLeft, ChevronRight, Download, Film, FolderPlus, ImagePlus, LoaderCircle, Plus, RefreshCw, Trash2, Upload, X } from '@lucide/vue'
import type { GalleryPhoto } from '~/composables/useAlbums'
import { refreshMediaElement, revealVideoFrame } from '~/composables/useMediaUrls'

const { albums, allPhotos, albumsLoading, albumPhotosLoadingMore, albumPhotosHasMore, loadAlbums, loadMorePhotos, retryPhoto, createAlbum, uploadToAlbum, deletePhoto } = useAlbums()
const { $supabase } = useNuxtApp()
const filter = ref('all'); const mediaFilter=ref<'all'|'image'|'video'>('all'); const createOpen = ref(false); const uploadOpen = ref(false); const name = ref(''); const description = ref(''); const targetAlbum = ref(''); const takenDate = ref(new Date().toISOString().slice(0,10)); const files = ref<File[]>([]); const previews = ref<string[]>([]); const busy = ref(false); const error = ref(''); const lightboxIndex = ref<number | null>(null)
const filteredPhotos = computed(() => (filter.value === 'all' ? allPhotos.value : allPhotos.value.filter(photo => photo.albumId === filter.value)).filter(item=>mediaFilter.value==='all'||item.mediaType===mediaFilter.value))
const currentPhoto = computed(() => lightboxIndex.value === null ? null : filteredPhotos.value[lightboxIndex.value])
async function handleGalleryScroll() { if (window.innerHeight + window.scrollY >= document.documentElement.scrollHeight - 500) await loadMorePhotos() }
onMounted(async () => { await loadAlbums(); window.addEventListener('scroll', handleGalleryScroll, { passive: true }) })
onBeforeUnmount(() => window.removeEventListener('scroll', handleGalleryScroll))
watch(albums, value => { if (!targetAlbum.value && value[0]) targetAlbum.value = value[0].id }, { immediate: true })
function openCreate() { error.value = ''; createOpen.value = true }
function closeCreate() { createOpen.value = false; error.value = ''; name.value = ''; description.value = '' }
function openUpload() { if (!albums.value.length) { openCreate(); return } error.value = ''; uploadOpen.value = true }
function chooseFiles(event: Event) { const chosen = Array.from((event.target as HTMLInputElement).files || []).filter(file => file.type.startsWith('image/')||file.type.startsWith('video/')); if (chosen.some(file => file.type.startsWith('image/')?file.size>8*1024*1024:file.size>50*1024*1024)) { error.value='照片不能超过 8 MB，视频不能超过 50 MB'; return } files.value=chosen; previews.value.forEach(URL.revokeObjectURL); previews.value=chosen.map(URL.createObjectURL); error.value='' }
async function saveAlbum(){if(!name.value.trim()){error.value='请输入相册名称';return}busy.value=true;try{await createAlbum(name.value.trim(),description.value.trim());closeCreate()}catch(e:any){error.value=e.message}finally{busy.value=false}}
async function savePhotos(){if(!targetAlbum.value||!files.value.length){error.value='请选择相册和照片';return}busy.value=true;try{await uploadToAlbum(targetAlbum.value,files.value,takenDate.value);closeUpload()}catch(e:any){error.value=e.message}finally{busy.value=false}}
function closeUpload(){uploadOpen.value=false;files.value=[];previews.value.forEach(URL.revokeObjectURL);previews.value=[];error.value=''}
function navigate(step:number){if(lightboxIndex.value===null||!filteredPhotos.value.length)return;lightboxIndex.value=(lightboxIndex.value+step+filteredPhotos.value.length)%filteredPhotos.value.length}
function revealVideo(event:Event){ revealVideoFrame(event) }
async function refreshMedia(event: Event, photo: GalleryPhoto) { await refreshMediaElement(event, $supabase, photo.path, photo.source === 'memory' ? 'memory-photos' : 'album-media', photo.mediaType === 'image' ? { width: 1200, height: 1200, resize: 'contain', quality: 82 } : undefined) }
async function download(photo:GalleryPhoto){const response=await fetch(photo.url);const blob=await response.blob();const link=document.createElement('a');link.href=URL.createObjectURL(blob);link.download=`couple-space-${photo.takenDate}.${photo.mediaType==='video'?'mp4':'jpg'}`;link.click();URL.revokeObjectURL(link.href)}
async function remove(photo:GalleryPhoto){try{if(confirm('确定删除这张照片吗？')){await deletePhoto(photo);lightboxIndex.value=null}}catch(e:any){alert(e.message)}}
</script>
<template>
  <section class="album-view">
    <header class="album-header"><div><p class="eyebrow">OUR GALLERY</p><h1>双人相册</h1><span>所有一起看过的风景，都留在这里。</span></div><div><button class="soft-action" type="button" @click="openCreate"><FolderPlus :size="18"/> 新建相册</button><button class="dark-action" type="button" @click="openUpload"><Upload :size="18"/> 上传照片</button></div></header>
    <div class="media-switch" role="tablist" aria-label="媒体类型"><button type="button" role="tab" :aria-selected="mediaFilter==='all'" :class="{active:mediaFilter==='all'}" @click="mediaFilter='all'">全部 <small>{{allPhotos.length}}</small></button><button type="button" role="tab" :aria-selected="mediaFilter==='image'" :class="{active:mediaFilter==='image'}" @click="mediaFilter='image'">照片 <small>{{allPhotos.filter(x=>x.mediaType==='image').length}}</small></button><button type="button" role="tab" :aria-selected="mediaFilter==='video'" :class="{active:mediaFilter==='video'}" @click="mediaFilter='video'">视频 <small>{{allPhotos.filter(x=>x.mediaType==='video').length}}</small></button></div><nav class="album-filters" aria-label="相册筛选"><button :class="{active:filter==='all'}" type="button" @click="filter='all'">全部相册</button><button v-for="album in albums" :key="album.id" :class="{active:filter===album.id}" type="button" @click="filter=album.id">{{album.name}} <small>{{album.photoCount}}</small></button><button :class="{active:filter==='memories'}" type="button" @click="filter='memories'">时光轴 <small>{{allPhotos.filter(p=>p.source==='memory').length}}</small></button></nav>
    <div v-if="albumsLoading" class="gallery-state"><LoaderCircle class="spin" :size="24"/> 正在整理照片</div>
    <div v-else-if="!filteredPhotos.length" class="gallery-state empty"><ImagePlus :size="38"/><h3>这个相册还是空的</h3><p>上传照片，或者先在时光轴中记录一段回忆。</p><button type="button" @click="openUpload">{{albums.length?'上传照片':'创建第一个相册'}}</button></div>
    <div v-else class="photo-wall"><button v-for="(photo,index) in filteredPhotos" :key="photo.id" type="button" @click="photo.url ? (lightboxIndex=index) : retryPhoto(photo)"><div v-if="!photo.url" class="media-placeholder"><template v-if="photo.loadState==='error'"><RefreshCw :size="19"/><small>加载失败，点击重试</small></template><LoaderCircle v-else class="spin" :size="20"/></div><template v-else><video v-if="photo.mediaType==='video'" :src="photo.url" muted playsinline preload="auto" @loadedmetadata="revealVideo" @error="refreshMedia($event, photo)"/><img v-else :src="photo.url" :alt="photo.caption||'情侣相册照片'" loading="lazy" decoding="async" @error="refreshMedia($event, photo)"><i v-if="photo.mediaType==='video'"><Film :size="22"/>视频</i><span><CalendarDays :size="13"/>{{photo.takenDate}} · {{photo.uploaderName}} 添加</span></template></button></div>
    <div v-if="albumPhotosLoadingMore" class="gallery-loading-more"><LoaderCircle class="spin" :size="15"/>正在加载更多回忆</div><div v-else-if="!albumPhotosHasMore && filteredPhotos.length" class="gallery-end">已经看到全部共同回忆</div>

    <div v-if="createOpen" class="modal-overlay" @click.self="closeCreate"><section class="album-modal"><header><div><p class="eyebrow">NEW ALBUM</p><h2>新建相册</h2></div><button type="button" aria-label="关闭" @click="closeCreate"><X :size="20"/></button></header><label><span>相册名称</span><input v-model="name" maxlength="40" placeholder="例如：第一次旅行"></label><label><span>相册描述</span><textarea v-model="description" maxlength="160" rows="3" placeholder="写一句关于这个相册的话"/></label><p v-if="error" class="modal-error">{{error}}</p><footer><button type="button" @click="closeCreate">取消</button><button class="confirm" type="button" :disabled="busy" @click="saveAlbum"><Plus :size="17"/> 创建相册</button></footer></section></div>
    <div v-if="uploadOpen" class="modal-overlay" @click.self="closeUpload"><section class="album-modal upload-modal"><header><div><p class="eyebrow">ADD MEDIA</p><h2>上传照片或视频</h2></div><button type="button" aria-label="关闭" @click="closeUpload"><X :size="20"/></button></header><div class="upload-fields"><label><span>放入相册</span><select v-model="targetAlbum"><option v-for="album in albums" :key="album.id" :value="album.id">{{album.name}}</option></select></label><label><span>拍摄日期</span><input v-model="takenDate" type="date"></label></div><div v-if="previews.length" class="upload-previews"><template v-for="(preview,index) in previews" :key="preview"><video v-if="files[index]?.type.startsWith('video/')" :src="preview" muted playsinline preload="auto" @loadedmetadata="revealVideo"/><img v-else :src="preview" alt="待上传照片"></template></div><label class="file-drop"><ImagePlus :size="23"/><strong>选择照片或视频</strong><small>照片不超过 8 MB，视频不超过 50 MB</small><input type="file" accept="image/jpeg,image/png,image/webp,image/gif,video/mp4,video/webm,video/quicktime" multiple hidden @change="chooseFiles"></label><p v-if="error" class="modal-error">{{error}}</p><footer><button type="button" @click="closeUpload">取消</button><button class="confirm" type="button" :disabled="busy" @click="savePhotos"><LoaderCircle v-if="busy" class="spin" :size="17"/><Upload v-else :size="17"/> 上传 {{files.length||''}} 项</button></footer></section></div>
    <div v-if="currentPhoto" class="lightbox"><button class="lightbox-close" type="button" aria-label="关闭" @click="lightboxIndex=null"><X :size="23"/></button><button class="lightbox-nav prev" type="button" aria-label="上一项" @click="navigate(-1)"><ChevronLeft :size="26"/></button><figure><video v-if="currentPhoto.mediaType==='video'" :src="currentPhoto.url" controls autoplay playsinline/><img v-else :src="currentPhoto.url" alt="全屏照片"><figcaption><div><strong>{{currentPhoto.albumName}}</strong><span>{{currentPhoto.takenDate}} · {{currentPhoto.uploaderName}} 添加</span></div><div><button type="button" title="下载原文件" @click="download(currentPhoto)"><Download :size="19"/></button><button type="button" title="删除" @click="remove(currentPhoto)"><Trash2 :size="19"/></button></div></figcaption></figure><button class="lightbox-nav next" type="button" aria-label="下一项" @click="navigate(1)"><ChevronRight :size="26"/></button></div>
  </section>
</template>
<style scoped>
.album-header h1{font-weight:800;color:#4d2c57}.soft-action,.dark-action{border-radius:22px!important}.dark-action{background:linear-gradient(135deg,#8b4db9,#d85f99)!important;border:0!important;box-shadow:0 12px 25px rgba(131,63,157,.2)}.album-filters button{border-radius:18px!important}.album-filters button.active{background:linear-gradient(135deg,#ead2ff,#ffd9e7)!important;color:#713a99!important}.photo-wall>button{border:3px solid rgba(255,255,255,.82)!important;border-radius:24px!important;box-shadow:0 14px 34px rgba(101,57,120,.12)}.album-modal{border-radius:32px!important;background:linear-gradient(145deg,#fffaff,#fff4f9)!important}.album-modal input,.album-modal textarea,.album-modal select{border-radius:19px!important}.album-modal footer .confirm{background:linear-gradient(135deg,#8b4db9,#d85f99)!important;border-radius:21px!important}
.album-view{width:min(100%,1180px);margin:0 auto}.album-header{display:flex;align-items:flex-end;justify-content:space-between;gap:24px;padding:14px 0 26px}.album-header h1{margin:0 0 7px;font-size:32px}.album-header>div>span{color:#89818f;font-size:13px}.album-header>div:last-child{display:flex;gap:9px}.soft-action,.dark-action{display:flex;align-items:center;gap:8px;min-height:44px;padding:0 15px;border:1px solid #e5dfe8;border-radius:14px;background:#fff;font-size:11px;font-weight:750;cursor:pointer}.dark-action{border-color:#332f3a;background:#332f3a;color:#fff}.album-filters{display:flex;gap:8px;overflow-x:auto;padding:2px 0 18px}.album-filters button{white-space:nowrap;padding:9px 12px;border:0;border-radius:12px;background:transparent;color:#837b8b;font-size:11px;font-weight:700;cursor:pointer}.album-filters button.active{background:#eee9f8;color:#765ca6}.album-filters small{margin-left:4px;opacity:.65}.photo-wall{columns:4 220px;column-gap:12px}.photo-wall>button{position:relative;overflow:hidden;width:100%;margin:0 0 12px;padding:0;border:0;border-radius:16px;background:#eeeaf1;break-inside:avoid;cursor:zoom-in}.photo-wall img{display:block;width:100%;min-height:170px;max-height:410px;object-fit:cover;transition:.25s}.photo-wall button:hover img{transform:scale(1.025)}.photo-wall span{position:absolute;right:8px;bottom:8px;left:8px;display:flex;align-items:center;gap:5px;padding:8px 9px;border-radius:10px;background:rgba(34,29,39,.58);color:#fff;font-size:9px;backdrop-filter:blur(10px)}.gallery-state{display:flex;align-items:center;justify-content:center;gap:9px;min-height:380px;color:#918999;font-size:12px}.gallery-state.empty{flex-direction:column}.gallery-state.empty svg{color:#b69cd8}.gallery-state h3{margin:8px 0 0;color:#403a46}.gallery-state p{margin:0}.gallery-state button{margin-top:10px;padding:10px 14px;border:0;border-radius:12px;background:#eee9f8;color:#765ca6;font-weight:700}.modal-overlay{position:fixed;z-index:60;inset:0;display:grid;place-items:center;padding:20px;background:rgba(45,39,52,.28);backdrop-filter:blur(10px)}.album-modal{width:min(100%,480px);padding:27px;border:1px solid rgba(255,255,255,.9);border-radius:24px;background:#fdfcfe;box-shadow:0 28px 75px rgba(50,39,61,.18)}.album-modal>header{display:flex;justify-content:space-between;margin-bottom:23px}.album-modal h2{margin:0;font-size:23px}.album-modal>header button{display:grid;place-items:center;width:37px;height:37px;border:0;border-radius:12px;background:#f0ebf5}.album-modal>label,.upload-fields label{display:block;margin-top:15px}.album-modal label>span{display:block;margin-bottom:8px;color:#655e6c;font-size:11px;font-weight:700}.album-modal input,.album-modal textarea,.album-modal select{width:100%;padding:13px;border:1px solid #e5dfe8;border-radius:13px;outline:0;background:#fff;font:inherit;font-size:12px}.album-modal textarea{resize:vertical}.album-modal footer{display:flex;justify-content:flex-end;gap:9px;margin-top:22px}.album-modal footer button{display:flex;align-items:center;gap:7px;min-height:42px;padding:0 16px;border:0;border-radius:13px;background:#f0ebf3;font-size:11px;font-weight:700}.album-modal footer .confirm{background:#332f3a;color:#fff}.upload-modal{width:min(100%,580px)}.upload-fields{display:grid;grid-template-columns:1fr 1fr;gap:12px}.upload-fields label{margin-top:0}.upload-previews{display:grid;grid-template-columns:repeat(5,1fr);gap:6px;margin-top:15px}.upload-previews img{width:100%;aspect-ratio:1;border-radius:10px;object-fit:cover}.file-drop{display:flex!important;flex-direction:column;align-items:center;padding:23px;border:1px dashed #c9b9de;border-radius:15px;background:#f7f3fb;color:#795fa0;cursor:pointer}.file-drop strong{font-size:12px}.file-drop small{margin-top:4px;color:#9b91a3;font-size:9px}.modal-error{color:#bd5776;font-size:10px}.lightbox{position:fixed;z-index:70;inset:0;display:grid;grid-template-columns:70px minmax(0,1fr) 70px;align-items:center;background:rgba(20,17,23,.92);backdrop-filter:blur(15px)}.lightbox figure{display:flex;flex-direction:column;align-items:center;justify-content:center;height:100vh;margin:0;padding:28px 0}.lightbox figure>img{max-width:100%;max-height:calc(100vh - 105px);object-fit:contain;border-radius:8px}.lightbox figcaption{display:flex;justify-content:space-between;width:min(100%,850px);padding:14px 4px;color:#fff}.lightbox figcaption strong,.lightbox figcaption span{display:block}.lightbox figcaption strong{font-size:12px}.lightbox figcaption span{margin-top:3px;color:#aaa3ae;font-size:10px}.lightbox figcaption>div:last-child{display:flex;gap:8px}.lightbox figcaption button,.lightbox-close,.lightbox-nav{display:grid;place-items:center;width:40px;height:40px;border:0;border-radius:13px;background:rgba(255,255,255,.1);color:#fff;cursor:pointer}.lightbox-close{position:absolute;z-index:2;top:20px;right:20px}.lightbox-nav{margin:auto}.spin{animation:spin 1s linear infinite}@keyframes spin{to{transform:rotate(360deg)}}
@media(max-width:650px){.album-header{align-items:flex-start}.album-header h1{font-size:26px}.album-header>div>span{font-size:11px}.album-header>div:last-child{gap:6px}.soft-action,.dark-action{width:43px;padding:0;justify-content:center;font-size:0}.photo-wall{columns:2 130px;column-gap:8px}.photo-wall>button{margin-bottom:8px;border-radius:12px}.photo-wall img{min-height:120px}.photo-wall span{display:none}.modal-overlay{align-items:end;padding:0}.album-modal{max-height:92vh;overflow:auto;padding:22px 18px calc(22px + env(safe-area-inset-bottom));border-radius:24px 24px 0 0}.upload-fields{grid-template-columns:1fr}.upload-previews{grid-template-columns:repeat(4,1fr)}.lightbox{grid-template-columns:45px minmax(0,1fr) 45px}.lightbox figure{padding:55px 0 12px}.lightbox figure>img{max-height:calc(100vh - 145px)}.lightbox-nav{width:38px;height:38px;background:rgba(255,255,255,.07)}}
</style>
